        case 5:
            return MoonGuidance(title: "Усвоение опыта", description: "День про переработку впечатлений и выбор того, что можно взять с собой дальше. Хорошо учиться, собирать факты, уточнять детали.", focus: "Обучение", actions: ["Разберите заметки и документы", "Попросите недостающую информацию", "Не перегружайте себя новыми обещаниями"])
